defmodule MyApp.ShellExecutor do
  @moduledoc """
  A service to execute shell commands for DevOps automation.
  """

  @doc """
  Executes a shell command using `sh -c`.

  Accepts a single string `user_command` which will be passed to `sh -c`.
  Returns `{:ok, stdout, stderr, exit_status}` on successful execution,
  or `{:error, reason}` if the input is invalid.

  ## Examples

      iex> MyApp.ShellExecutor.execute("echo Hello, Elixir!")
      {:ok, "Hello, Elixir!\\n", "", 0}

      iex> MyApp.ShellExecutor.execute("ls /nonexistent_path")
      {:ok, "", "ls: /nonexistent_path: No such file or directory\\n", 1}

      iex> MyApp.ShellExecutor.execute(123)
      {:error, :invalid_command_type}
  """
  def execute(user_command) when is_binary(user_command) do
    # System.cmd returns {stdout, stderr, exit_status}
    {stdout, stderr, exit_status} = System.cmd("sh", ["-c", user_command])
    {:ok, stdout, stderr, exit_status}
  end

  def execute(_invalid_command) do
    {:error, :invalid_command_type}
  end
end

